+void QSFAMlaTiling::ZeroTensorProcess() const
+{
+    if (qsfaInfo_->s2Size == 0) {
+        /*
+         * 1024，空tensor场景下，作为默认值完成后续计算
+         * 避免matmal tiling  softmax tiling异常
+         * kernel计算使用真实的seqSize=0, 与actuseq_len流程归一
+         */
+        qsfaInfo_->s2Size = 1024;
+    }
+}
