+ge::graphStatus QSFATilingCheck::CheckActualSeqLens()
+{
+    if (ge::GRAPH_SUCCESS != CheckActualSeqLensDType() ||
+        ge::GRAPH_SUCCESS != CheckActualSeqLensShape()) {
+        return ge::GRAPH_FAILED;
+    }
+    return ge::GRAPH_SUCCESS;
+}
